// pending 배치의 상세를 파싱해 요약 프롬프트 생성 + 연차필터로 action 결정.
// [All Items] SELECT 결과(rows)와 상세조회($input)를 인덱스로 짝짓는다.
const rows = $('pending 배치 조회').all();
const details = $input.all();
const maxYears = Number($('설정 (Config)').first().json.maxCareerYears);
const out = [];
for (let i = 0; i < rows.length; i++) {
  const r = rows[i].json;                 // id, source, job_id, company, title, url, min_career, max_career, attempts
  const d = details[i]?.json || {};
  let responsibility = '', qualifications = '', preferred = '', ok = true;
  if (d.result) {
    responsibility = d.result.responsibility || '';
    qualifications = d.result.qualifications || '';
    preferred      = d.result.preferredRequirements || '';
  } else if (d.data?.job?.detail) {
    const det = d.data.job.detail;
    responsibility = det.main_tasks || det.intro || '';
    qualifications = det.requirements || '';
    preferred      = det.preferred_points || '';
  } else { ok = false; }                  // 상세 파싱 실패

  // 연차 보완(원티드는 상세에서)
  let minCareer = r.min_career, maxCareer = r.max_career;
  if (d.data?.job) {
    if (minCareer == null) minCareer = d.data.job.annual_from ?? null;
    if (maxCareer == null) maxCareer = d.data.job.annual_to ?? null;
  }
  if (maxCareer != null && maxCareer > 20) maxCareer = null;

  let action;
  if (!ok) action = 'fail';
  else if (Number.isFinite(maxYears) && minCareer != null && minCareer > maxYears) action = 'skip';
  else action = 'summarize';

  const prompt = `제목: ${r.title}\n회사: ${r.company}\n\n[주요업무]\n${responsibility}\n\n[자격요건]\n${qualifications}\n\n[우대사항]\n${preferred}`;
  out.push({ json: { id: r.id, source: r.source, job_id: r.job_id, company: r.company, title: r.title, url: r.url, attempts: r.attempts, minCareer, maxCareer, action, prompt } });
}
return out;

// 요약 성공 → done UPDATE, 실패(빈 응답) → 재시도 캡. [Each Item]
const m = $('처리 준비').item.json;
const content = $json.choices?.[0]?.message?.content;
const esc = (v) => v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
const num = (v) => (v == null || v === '') ? 'NULL' : (Number.isFinite(Number(v)) ? Number(v) : 'NULL');
const arr = (list) => { const a = (list || []).map(s => `'${String(s).replace(/'/g, "''")}'`); return a.length ? `ARRAY[${a.join(',')}]::text[]` : `'{}'::text[]`; };
let sql;
if (content) {
  let stacks = []; const mm = content.match(/기술스택\s*[:：]\s*(.+)/);
  if (mm) stacks = mm[1].split(/[,·]/).map(s => s.trim()).filter(Boolean);
  // 점프잇은 수집 때 넣은 tech_stacks 유지, 원티드는 요약에서 추출한 값으로 채움
  sql = `UPDATE jobs SET status='done', summary=${esc(content)}, min_career=${num(m.minCareer)}, max_career=${num(m.maxCareer)}, tech_stacks=CASE WHEN cardinality(tech_stacks)>0 THEN tech_stacks ELSE ${arr(stacks)} END, attempts=attempts+1, updated_at=now() WHERE source=${esc(m.source)} AND job_id=${esc(m.job_id)};`;
} else {
  const maxAtt = Number($('설정 (Config)').first().json.maxAttempts) || 3;
  sql = `UPDATE jobs SET status=CASE WHEN attempts+1 >= ${maxAtt} THEN 'failed' ELSE 'pending' END, attempts=attempts+1, updated_at=now() WHERE source=${esc(m.source)} AND job_id=${esc(m.job_id)};`;
}
return { json: { sql } };

// skip(연차제외) → 'skipped', fail(상세실패) → 재시도 캡. [Each Item]
const m = $json;
const esc = (v) => v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
const maxAtt = Number($('설정 (Config)').first().json.maxAttempts) || 3;
let sql;
if (m.action === 'skip') {
  sql = `UPDATE jobs SET status='skipped', attempts=attempts+1, updated_at=now() WHERE source=${esc(m.source)} AND job_id=${esc(m.job_id)};`;
} else {
  sql = `UPDATE jobs SET status=CASE WHEN attempts+1 >= ${maxAtt} THEN 'failed' ELSE 'pending' END, attempts=attempts+1, updated_at=now() WHERE source=${esc(m.source)} AND job_id=${esc(m.job_id)};`;
}
return { json: { sql } };
